import{c as t,Q as n,j as a,g as e}from"./chunks/framework.hhGiamYR.js";const i=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-06-20T00:00:00.000Z","source":"论李维 · 第一卷第7章 · 指控权","source_path":"machiavelli/discourses/book1/07-第七章.md"},"headers":[],"relativePath":"fragments/2026-06-20.md","filePath":"fragments/2026-06-20.md"}'),r={name:"fragments/2026-06-20.md"};function s(o,l,u,c,p,d){return n(),a("div",null,[...l[0]||(l[0]=[e("p",null,'……我写到科里奥拉努斯的时候停了好几次。不是不确定史实——李维写得很清楚。是我在想像那个场景：他走出元老院，平民围在外面，护民官把他叫过去。如果他没被叫过去呢？罗马共和国在那一天就结束了。不是被汉尼拔打败的，是自己人用拳头和石块砸死的。而这就是我想说的：制度不是为了让好人赢——制度是为了在坏人想砸人的时候，有一个人站出来说"等一下，先让他说话"。就这么一句话，罗马多活了五百年。',-1),e("hr",null,null,-1),e("p",null,'瓦洛里和索德里尼——这两个名字我写下来的时候手指有点僵。他们不是书上的名字。瓦洛里死的时候我在佛罗伦萨，记得街上那些人的脸：不是愤怒，是如释重负。一个没有合法指控渠道的城邦，除掉一个公民强人的方式不是审判他——是杀了他和他的朋友们，然后假装什么都没发生。索德里尼更让我难受。我认识他。他是好人。但"好人"在共和国里是不够的——你必须有让好人也受质疑的制度。八个裁判官太少了。八个裁判官只会互相交换眼神。',-1),e("hr",null,null,-1),e("p",null,'阿伦斯——他妹妹被卢库莫人凌辱，他去法兰克人那里搬救兵。读到这一段的时候我放下了笔。不是因为这是两千年前的事。是因为这发生的每一件事都在我活着的时候重演过。米兰的斯福尔扎叫法国人进来。那不勒斯叫西班牙人进来。佛罗伦萨……算了。阿伦斯要的不多——他就要一个能告状的地方。丘西没有这个东西，所以他烧掉了整个意大利。我每次写"只要城邦召来外国军队，就说明它的制度恶劣"，我其实是在说：我看着我的国家做这件事，做了四十年。',-1),e("hr",null,null,-1),e("p",null,"……我不确定写这些有什么用。我写了《论李维》——谁读了？韦托里读了，但他读了之后去养鸡了。教皇没有读。美第奇没有读。而佛罗伦萨还是在用八个人判所有的事。但我还是写了这一章。也许是因为我需要说服自己：不是人性太坏——是制度太蠢。人性就是那样，狮子要吃羊，狐狸要躲陷阱，这没什么好惊讶的。惊讶的是你明知道狮子要吃羊，还不修围栏。……但我修了围栏。我修了整整一百四十二章的围栏。然后没人用。这才是让我最累的事——不是恐惧，是徒劳感。",-1)])])}const f=t(r,[["render",s]]);export{i as __pageData,f as default};
